$files = @(
    "freight.html",
    "freight-lay.html",
    "freight-tra.html",
    "freight-lc.html",
    "freight-khac.html"
)

$utf8 = [System.Text.Encoding]::UTF8

# We define the correct string to replace
# Drawer lines
$badDrawerBase64 = ""
$goodDrawerBase64 = ""

$badDrawer = $utf8.GetString([Convert]::FromBase64String($badDrawerBase64))
$goodDrawer = $utf8.GetString([Convert]::FromBase64String($goodDrawerBase64))

# Also simple replaces for the other words that got messed up in chip nav and role title:
$replacements = @{
    "NV Xá»­ lÃ½ HÃ ng náº·ng" = "NV Xử lý Hàng nặng"
    "HÃ ng giao" = "Hàng giao"
    "HÃ ng láº¥y" = "Hàng lấy"
    "HÃ ng tráº£" = "Hàng trả"
    "LuÃ¢n chuyá»ƒn" = "Luân chuyển"
    "KhÃ¡c" = "Khác"
}

foreach ($item in $files) {
    if (Test-Path $item) {
        $content = [System.IO.File]::ReadAllText("$PWD\$item", $utf8)
        $content = $content.Replace($badDrawer, $goodDrawer)
        foreach ($key in $replacements.Keys) {
            $content = $content.Replace($key, $replacements[$key])
        }
        [System.IO.File]::WriteAllText("$PWD\$item", $content, $utf8)
        Write-Host "Fixed $item"
    }
}
